3429	\begin{lemma}
3430	
3431	\leanok
3432	[The slice-to-geometric isomorphism in pullback form (gap1, C, step 4')]
3433	  \label{lem:over_restrict_pullback_iso}
3434	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictPullbackIso}
3435	  \uses{lem:over_restrict_iso, lem:modules_restrictFunctorIsoPullback_mathlib,
3436	    lem:modules_pullback_mathlib}
3437	  \textit{The pullback packaging of the slice-touching bridge; the form consumed by the P1 transport.}
3438	  With \(X\) and \(U \subseteq X\) as above and \(M\) a sheaf of modules on \(X\), the transport of the
3439	  abstract Grothendieck-slice restriction \(M.\mathrm{over}\,U\) under the step-3 equivalence functor
3440	  (\cref{def:over_restrict_equiv}) is canonically isomorphic to the inverse-image (pullback) of \(M\)
3441	  along the open immersion \(U.\iota\):
3442	  \[
3443	    (\mathrm{overRestrictEquiv}\,U).\mathrm{functor}.\mathrm{obj}\,(M.\mathrm{over}\,U)
3444	      \;\cong\; (U.\iota^{*})\,M
3445	  \]
3446	  (\cref{lem:modules_pullback_mathlib}). This is the pullback packaging of the slice-touching bridge
3447	  \cref{lem:over_restrict_iso}; it is exactly the form in which a presentation of
3448	  \(M.\mathrm{over}\,U\) is transported into a presentation of the geometric pullback \(U.\iota^{*}M\),
3449	  and it is the ingredient consumed by the per-element local-tilde transport
3450	  \cref{lem:isIso_fromTildeΓ_basicOpen_of_quasicoherent}.
3451	\end{lemma}
3452	\begin{proof}
3453	  \uses{lem:over_restrict_iso, lem:modules_restrictFunctorIsoPullback_mathlib}
3454	  Compose the slice-to-geometric isomorphism \cref{lem:over_restrict_iso}, which identifies the
3455	  transported slice restriction with the geometric restriction
3456	  \((\mathrm{restrictFunctor}\,U.\iota).\mathrm{obj}\,M\), with the component at \(M\) of the natural
3457	  isomorphism \(\mathrm{restrictFunctorIsoPullback}\,U.\iota\)
3458	  (\cref{lem:modules_restrictFunctorIsoPullback_mathlib}) identifying the geometric restriction with
3459	  the pullback \(U.\iota^{*}M\).
3460	\end{proof}
