3522	\begin{definition}\leanok
3523	[Transport of a slice presentation to a geometric presentation]
3524	  \label{def:over_restrict_presentation}
3525	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictPresentation}
3526	  \uses{def:over_restrict_unit_iso, lem:over_restrict_pullback_iso, lem:presentation_map_mathlib}
3527	  \textit{A slice presentation yields a presentation of the geometric pullback.}
3528	  Let \(U \subseteq X\) be open and \(M\) a sheaf of modules on \(X\). A
3529	  presentation of the abstract Grothendieck-slice restriction \(M.\mathrm{over}\,U\)
3530	  yields a presentation of the geometric pullback \((U.\iota^{*})\,M\):
3531	  \[
3532	    (M.\mathrm{over}\,U).\mathrm{Presentation}
3533	      \;\longrightarrow\;
3534	    \bigl((U.\iota^{*})\,M\bigr).\mathrm{Presentation} .
3535	  \]
3536	\end{definition}
3537	\begin{proof}
3538	  \uses{def:over_restrict_unit_iso, lem:over_restrict_pullback_iso, lem:presentation_map_mathlib}
3539	  Apply the functorial transport of presentations \(\mathrm{Presentation.map}\)
3540	  (\cref{lem:presentation_map_mathlib}) along the step-3 slice equivalence functor
3541	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}\), using
3542	  \cref{def:over_restrict_unit_iso} to identify the image of the structure-sheaf
3543	  (unit) module with the target unit module; this lands a presentation of the
3544	  transported slice module
3545	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}.\mathrm{obj}\,(M.\mathrm{over}\,U)\).
3546	  Finally transport across the pullback packaging isomorphism
3547	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}.\mathrm{obj}\,(M.\mathrm{over}\,U)
3548	  \cong (U.\iota^{*})\,M\) (\cref{lem:over_restrict_pullback_iso}) via
3549	  \(\mathrm{Presentation.ofIsIso}\), giving a presentation of the geometric
3550	  pullback \((U.\iota^{*})\,M\).
3551	\end{proof}
