3553	\begin{definition}\leanok
3554	[Per-cover-member geometric presentation from quasi-coherence data]
3555	  \label{def:presentation_pullback_iota_of_quasicoherentData}
3556	  \lean{AlgebraicGeometry.Scheme.Modules.presentationPullbackιOfQuasicoherentData}
3557	  \uses{def:over_restrict_presentation, lem:quasicoherentData_bind_mathlib}
3558	  \textit{Quasi-coherence data gives a presentation on each cover member's pullback.}
3559	  Let \(M\) be a sheaf of modules on \(X\), let \(q\) be quasi-coherence data for
3560	  \(M\), and let \(i\) be a cover index. There is a presentation of the geometric
3561	  pullback of \(M\) to the open subscheme \(q.X_i\):
3562	  \[
3563	    \bigl((q.X_i).\iota^{*}\,M\bigr).\mathrm{Presentation} .
3564	  \]
3565	\end{definition}
3566	\begin{proof}
3567	  \uses{def:over_restrict_presentation, lem:quasicoherentData_bind_mathlib}
3568	  The datum \(q\) packages, for each index \(i\), a slice presentation
3569	  \(q.\mathrm{presentation}\,i : (M.\mathrm{over}\,(q.X_i)).\mathrm{Presentation}\)
3570	  over the cover member \(q.X_i\) (the per-member presentations whose binding is
3571	  recorded by \(\mathrm{QuasicoherentData}\), \cref{lem:quasicoherentData_bind_mathlib}).
3572	  Feeding this slice presentation to \cref{def:over_restrict_presentation} at
3573	  \(U = q.X_i\) produces the desired presentation of the geometric pullback
3574	  \((q.X_i).\iota^{*}\,M\).
3575	\end{proof}
