3577	% --- (P1 prep) Affine-open presentation transport: slice → geometrize → affine-identify ---
3578	% Six project-bespoke Scheme.Modules helpers (no external source — Mathlib presentation/pullback
3579	% bookkeeping): they carry the global presentation of a cover member down to an arbitrary open W,
3580	% then transport it across the affine identification W ≅ Spec Γ(Z,W). Together they assemble the
3581	% general keystone lem:isIso_fromTildeΓ_presentationPullback, of which the basic-open P1 keystone
3582	% lem:isIso_fromTildeΓ_basicOpen_of_quasicoherent is the affine instance W = (q.X i).ι ⁻¹ᵁ D(r).
3583	
3584	\begin{definition}
3585	
3586	\leanok
3587	[Presentation of the geometric restriction to an open of a cover member]
3588	  \label{def:presentation_pullback_iota_restrict}
3589	  \lean{AlgebraicGeometry.Scheme.Modules.presentationPullbackιRestrict}
3590	  \uses{def:presentation_pullback_iota_of_quasicoherentData, def:over_restrict_presentation,
3591	    lem:presentation_map_mathlib}
3592	  \textit{A global presentation on a cover member restricts to a presentation on any open of it.}
3593	  Let \(M\) be a sheaf of modules on \(X\) with quasi-coherence data \(q\), let \(i\) be a cover
3594	  index, and let \(W \subseteq Z\) be \emph{any} open of the cover-member subscheme
3595	  \(Z := (q.X_i).\mathrm{toScheme}\). Then the iterated geometric restriction
3596	  \((W.\iota^{*})\,\bigl((q.X_i).\iota^{*}\,M\bigr)\) of \(M\) admits a
3597	  \(\mathrm{SheafOfModules.Presentation}\) on the open subscheme \(W.\mathrm{toScheme}\).
3598	\end{definition}
3599	\begin{proof}
3600	  \uses{def:presentation_pullback_iota_of_quasicoherentData, def:over_restrict_presentation,
3601	    lem:presentation_map_mathlib}
3602	  Write \(N := (q.X_i).\iota^{*}\,M\), which carries the global presentation
3603	  \cref{def:presentation_pullback_iota_of_quasicoherentData} on \(Z\). Slice this global presentation
3604	  down to the Grothendieck-slice \(N.\mathrm{over}\,W\) by a single application of
3605	  \(\mathrm{Presentation.map}\) (\cref{lem:presentation_map_mathlib}) along the over-functor
3606	  \(\mathrm{pushforward}\,(\mathbf{1})\) — no iterated-slice equivalence is needed since \(N\) already
3607	  lives on the genuine scheme \(Z\). Then geometrize this slice presentation via
3608	  \cref{def:over_restrict_presentation} at \(U = W\), yielding a presentation of the geometric
3609	  restriction \((W.\iota^{*})\,N\) on \(W.\mathrm{toScheme}\).
3610	\end{proof}
